mapper.select:
select a.* from biz_instrument_attachment a inner join biz_instrument i on i.id = a.instrument_id and i.deleted = 0 where a.deleted = 0
and i.owner_user_id = #{operatorId}
and i.department_id = #{departmentId}
order by a.instrument_id asc, a.sort_no asc, a.id asc


select a.*
from biz_instrument_attachment a
inner join biz_instrument i on i.id = a.instrument_id and i.deleted = 0
where a.deleted = 0

  and i.owner_user_id = #{operatorId}


  and i.department_id = #{departmentId}

order by a.instrument_id asc, a.sort_no asc, a.id asc
limit #{offset}, #{pageSize}


select count(1)
from biz_instrument_attachment a
inner join biz_instrument i on i.id = a.instrument_id and i.deleted = 0
where a.deleted = 0

  and i.owner_user_id = #{operatorId}


  and i.department_id = #{departmentId}
